module top_module( A, B, Ci, S, Co );input A, B, Ci;
  output S, Co;
  wire   n1, n2, n3, n4;

  // Logic for the Full Adder Implementation
  assign n1 = A ^ B ^ Ci; // Sum output
  wire temp1_(A & B) | (B & Ci) = (A & B) | (B & Ci);
  wire temp2_(A & Ci) = (A & Ci);
  assign Co = temp1_(A & B) | (B & Ci) | temp2_(A & Ci); // Carry output
  assign S = n1; // Connecting Sum

endmodule
